import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { getLessons, createLesson, updateLesson, deleteLesson } from '../../api/client';

const TYPE_OPTS      = [{ v:'study', l:'Study' }, { v:'exam', l:'Exam' }];
const SHOW_OPTS      = [{ v:'full_row', l:'Full Row Show' }, { v:'topic_wise', l:'Topic Wise Show' }];
const TEST_SRC_OPTS  = [{ v:'from_study', l:'Take From Study' }, { v:'custom_bank', l:'Custom Question Bank' }];

const initForm = (order=0) => ({
  name:'', order, lesson_type:'study', show_type:'full_row',
  test_source:'from_study', pass_percentage:90, is_active:true,
});

export default function CategoryDetail() {
  const { examId, catId } = useParams();
  const navigate = useNavigate();
  const [lessons, setLessons] = useState([]);
  const [modal,   setModal]   = useState(null);
  const [form,    setForm]    = useState(initForm());
  const [err,     setErr]     = useState('');

  const load = () => getLessons(catId).then(r => setLessons(r.data));
  useEffect(() => { load(); }, [catId]);

  const openCreate = () => { setForm(initForm(lessons.length)); setModal('create'); setErr(''); };
  const openEdit   = l  => {
    setForm({ name:l.name, order:l.order, lesson_type:l.lesson_type,
              show_type:l.show_type, test_source:l.test_source,
              pass_percentage:l.pass_percentage, is_active:l.is_active });
    setModal(l); setErr('');
  };

  const save = async () => {
    try {
      if (modal === 'create') await createLesson({ ...form, category: catId });
      else                    await updateLesson(modal.id, form);
      setModal(null); load();
    } catch (e) { setErr(JSON.stringify(e.response?.data)); }
  };

  const remove = async id => {
    if (!window.confirm('Delete this lesson?')) return;
    await deleteLesson(id); load();
  };

  return (
    <div>
      <div className="breadcrumb">
        <Link to="/courses">Course Editor</Link> ›{' '}
        <Link to={`/courses/${examId}`}>Exam</Link> ›{' '}
        <span>Category Lessons</span>
      </div>
      <div className="page-header">
        <h2>📋 Lessons</h2>
        <button className="btn btn-primary" onClick={openCreate}>+ Add Lesson</button>
      </div>

      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>#</th><th>Name</th><th>Type</th><th>Show Type</th>
              <th>Test Source</th><th>Pass %</th><th>Status</th><th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {lessons.map((l, i) => (
              <tr key={l.id}>
                <td>{i + 1}</td>
                <td style={{ fontWeight:600, cursor:'pointer', color:'var(--primary)' }}
                    onClick={() => navigate(`/courses/${examId}/categories/${catId}/lessons/${l.id}`)}>
                  {l.name}
                </td>
                <td><span className={`badge ${l.lesson_type==='study'?'badge-blue':'badge-red'}`}>{l.lesson_type}</span></td>
                <td style={{ fontSize:12 }}>{l.show_type}</td>
                <td><span className="badge badge-gray">{l.test_source}</span></td>
                <td>{l.pass_percentage}%</td>
                <td><span className={`badge ${l.is_active?'badge-green':'badge-gray'}`}>{l.is_active?'Active':'Draft'}</span></td>
                <td>
                  <div style={{ display:'flex', gap:6 }}>
                    <button className="btn btn-icon btn-sm" onClick={() => openEdit(l)} title="Settings">⚙️</button>
                    {l.lesson_type === 'study' && (
                      <button className="btn btn-icon btn-sm"
                        onClick={() => navigate(`/courses/${examId}/categories/${catId}/lessons/${l.id}`)}
                        title="Open Lesson">📝</button>
                    )}
                    {l.test_source === 'custom_bank' && (
                      <button className="btn btn-icon btn-sm"
                        onClick={() => navigate(`/courses/${examId}/categories/${catId}/lessons/${l.id}/banks`)}
                        title="Question Banks">🏦</button>
                    )}
                    <button className="btn btn-icon btn-sm" onClick={() => remove(l.id)} title="Delete">🗑️</button>
                  </div>
                </td>
              </tr>
            ))}
            {lessons.length === 0 && (
              <tr><td colSpan={8} style={{ textAlign:'center', color:'var(--text-muted)', padding:32 }}>No lessons yet.</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Lesson Settings Modal */}
      {modal !== null && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ width:'min(560px,95vw)' }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>⚙️ Lesson Settings</h3>
              <button className="btn btn-icon" onClick={() => setModal(null)}>✕</button>
            </div>
            {err && <div className="alert alert-error">{err}</div>}

            <div className="form-group">
              <label>Lesson Name</label>
              <input value={form.name} onChange={e => setForm(f=>({...f,name:e.target.value}))}
                     placeholder="e.g. Lesson 1, Exam 3" />
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Type</label>
                <select value={form.lesson_type} onChange={e => setForm(f=>({...f,lesson_type:e.target.value}))}>
                  {TYPE_OPTS.map(o => <option key={o.v} value={o.v}>{o.l}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>Status</label>
                <select value={form.is_active} onChange={e => setForm(f=>({...f,is_active:e.target.value==='true'}))}>
                  <option value="true">Active</option>
                  <option value="false">Draft</option>
                </select>
              </div>
            </div>

            {form.lesson_type === 'study' && (
              <div className="form-group">
                <label>Show Type</label>
                <select value={form.show_type} onChange={e => setForm(f=>({...f,show_type:e.target.value}))}>
                  {SHOW_OPTS.map(o => <option key={o.v} value={o.v}>{o.l}</option>)}
                </select>
              </div>
            )}

            <div className="form-row">
              <div className="form-group">
                <label>Take Test — Source</label>
                <select value={form.test_source} onChange={e => setForm(f=>({...f,test_source:e.target.value}))}>
                  {TEST_SRC_OPTS.map(o => <option key={o.v} value={o.v}>{o.l}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>Pass Percentage (%)</label>
                <input type="number" min={0} max={100} value={form.pass_percentage}
                       onChange={e => setForm(f=>({...f,pass_percentage:+e.target.value}))} />
              </div>
            </div>

            <p style={{ fontSize:12, color:'var(--text-muted)', background:'#F6F9FF', borderRadius:8, padding:'8px 12px', marginTop:-4 }}>
              {form.test_source === 'from_study'
                ? '✅ Test uses correct_answer (col B) + wrong 1–3 from the study import.'
                : '🏦 Test uses active question banks. Configure banks after saving.'}
            </p>

            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={save}>Save Settings</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
